// Test-and-set atomic instruction
boolean test_and_set(boolean *target) {
    boolean rv = *target;
    *target = TRUE;
    return rv;
}

// Lock using test-and-set
typedef struct {
    volatile boolean locked;
} lock_t;

void init_lock(lock_t *lock) {
    lock->locked = FALSE;
}

void lock(lock_t *lock) {
    while (test_and_set(&lock->locked)) {
        // Busy wait - lock is held
    }
}

void unlock(lock_t *lock) {
    lock->locked = FALSE;
}

// Basic Semaphore implementation
class Semaphore {
    private int value;

    public Semaphore(int initial) {
        this.value = initial;
    }

    public synchronized void wait() {
        while (value <= 0) {
            try { wait(); } catch(InterruptedException e) {}
        }
        value--;
    }

    public synchronized void signal() {
        value++;
        notify();
    }
}

// Producer-Consumer with Semaphores
class Buffer {
    private static final int SIZE = 10;
    private Object[] buffer = new Object[SIZE];
    private int count = 0, in = 0, out = 0;

    private Semaphore mutex = new Semaphore(1);  // For mutual exclusion
    private Semaphore full = new Semaphore(0);   // Items in buffer
    private Semaphore empty = new Semaphore(SIZE); // Empty slots

    public void producer(Object item) {
        empty.wait();
        mutex.wait();

        buffer[in] = item;
        in = (in + 1) % SIZE;
        count++;

        mutex.signal();
        full.signal();
    }

    public Object consumer() {
        full.wait();
        mutex.wait();

        Object item = buffer[out];
        out = (out + 1) % SIZE;
        count--;

        mutex.signal();
        empty.signal();
        return item;
    }
}
